#include<bits/stdc++.h>
using namespace std;
int sum[100010],ans[100010],n,p[100010],id[100010];
vector<int> mp[100010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
int getsum(int l,int r)
{
    return query(r)-query(l-1);
}
bool cmp(int x,int y)
{
    return p[x]>p[y];
}
void dfs(int x)
{
    ans[x]-=getsum(1,p[x]);
    for(int i:mp[x])
    {
        dfs(i);
    }
    ans[x]+=getsum(1,p[x]);
    add(p[x],1);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&p[i]);
        id[i]=i;
    }
    sort(id+1,id+1+n,cmp);
    for(int i=1;i<=n;i++)
    {
        p[id[i]]=i;
    }
    for(int i=2;i<=n;i++)
    {
        int f;
        scanf("%d",&f);
        mp[f].push_back(i);
    }
    dfs(1);
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
